package ir.tahamohamadi.content.contact;
import ir.tahamohamadi.common.domain.LanguageCode; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.*;
@Entity @Table(name="contact_message") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ContactMessage { @Id private UUID id; @Column(name="sender_name",nullable=false,length=200) private String senderName; @Column(name="sender_email",nullable=false,length=320) private String senderEmail; @Getter(AccessLevel.NONE) @Column(nullable=false,columnDefinition="text") private String message; @Enumerated(EnumType.STRING) @Column(name="source_language",nullable=false,length=2) private LanguageCode sourceLanguage; @Enumerated(EnumType.STRING) @Column(nullable=false,length=20) private ContactMessageStatus status; @Column(name="submitted_at",nullable=false) private Instant submittedAt; @Column(name="read_at") private Instant readAt; @Column(name="archived_at") private Instant archivedAt;
 private ContactMessage(UUID id,String senderName,String senderEmail,String message,LanguageCode sourceLanguage,Instant submittedAt){this.id=Objects.requireNonNull(id);this.senderName=require(senderName,"senderName");this.senderEmail=require(senderEmail,"senderEmail");this.message=require(message,"message");this.sourceLanguage=Objects.requireNonNull(sourceLanguage);this.submittedAt=Objects.requireNonNull(submittedAt);this.status=ContactMessageStatus.NEW;} public static ContactMessage submit(UUID id,String senderName,String senderEmail,String message,LanguageCode sourceLanguage,Instant submittedAt){return new ContactMessage(id,senderName,senderEmail,message,sourceLanguage,submittedAt);} public String messageForAdministration(){return message;} public void markRead(Instant at){status=ContactMessageStatus.READ;readAt=Objects.requireNonNull(at);} public void archive(Instant at){status=ContactMessageStatus.ARCHIVED;archivedAt=Objects.requireNonNull(at);} private static String require(String v,String n){if(v==null||v.isBlank())throw new IllegalArgumentException(n+" must not be blank");return v.trim();} @Override public boolean equals(Object o){return this==o||(o instanceof ContactMessage m&&id.equals(m.id));} @Override public int hashCode(){return id.hashCode();} @Override public String toString(){return "ContactMessage{id="+id+", status="+status+"}";} }
